using SchoolEnterprise.Models.Domain; using SchoolEnterprise.Services; namespace SchoolEnterprise.Repositories; public class MarkRepository(XmlStorageService storage) : BaseXmlRepository<StudentMark>(storage){ protected override string FileName=>"marks.xml"; public List<StudentMark> GetByRecordSemester(int recordId,int semester)=>GetAll().Where(x=>x.StudentRecordId==recordId&&x.Semester==semester).ToList(); public void Upsert(StudentMark i){var a=GetAll();var x=a.FindIndex(t=>t.StudentRecordId==i.StudentRecordId&&t.SubjectId==i.SubjectId&&t.Semester==i.Semester);if(x>=0)a[x]=i;else a.Add(i);SaveAll(a);} }
